use crate::x86::assembler::*;
use crate::x86::operands::*;
use super::super::opcodes::*;
use crate::core::emitter::*;
use crate::core::operand::*;

/// A dummy operand that represents no register. Here just for simplicity.
const NOREG: Operand = Operand::new();

/// `KANDNW` (KANDNW). 
/// Performs a bitwise AND NOT between the vector mask k2 and the vector mask k3, and writes the result into vector mask k1.
///
///
/// For more details, see the [Intel manual](https://www.felixcloutier.com/x86/KANDNW%3AKANDNB%3AKANDNQ%3AKANDND.html).
///
/// Supported operand variants:
///
/// ```text
/// +---+------------------+
/// | # | Operands         |
/// +---+------------------+
/// | 1 | KReg, KReg, KReg |
/// +---+------------------+
/// ```
pub trait KandnwEmitter<A, B, C> {
    fn kandnw(&mut self, op0: A, op1: B, op2: C);
}

impl<'a> KandnwEmitter<KReg, KReg, KReg> for Assembler<'a> {
    fn kandnw(&mut self, op0: KReg, op1: KReg, op2: KReg) {
        self.emit(KANDNWKKK, op0.as_operand(), op1.as_operand(), op2.as_operand(), &NOREG);
    }
}

/// `KANDW` (KANDW). 
/// Performs a bitwise AND between the vector mask k2 and the vector mask k3, and writes the result into vector mask k1.
///
///
/// For more details, see the [Intel manual](https://www.felixcloutier.com/x86/KANDW%3AKANDB%3AKANDQ%3AKANDD.html).
///
/// Supported operand variants:
///
/// ```text
/// +---+------------------+
/// | # | Operands         |
/// +---+------------------+
/// | 1 | KReg, KReg, KReg |
/// +---+------------------+
/// ```
pub trait KandwEmitter<A, B, C> {
    fn kandw(&mut self, op0: A, op1: B, op2: C);
}

impl<'a> KandwEmitter<KReg, KReg, KReg> for Assembler<'a> {
    fn kandw(&mut self, op0: KReg, op1: KReg, op2: KReg) {
        self.emit(KANDWKKK, op0.as_operand(), op1.as_operand(), op2.as_operand(), &NOREG);
    }
}

/// `KMOVW` (KMOVW). 
/// Copies values from the source operand (second operand) to the destination operand (first operand). The source and destination operands can be mask registers, memory location or general purpose. The instruction cannot be used to transfer data between general purpose registers and or memory locations.
///
///
/// For more details, see the [Intel manual](https://www.felixcloutier.com/x86/KMOVW%3AKMOVB%3AKMOVQ%3AKMOVD.html).
///
/// Supported operand variants:
///
/// ```text
/// +---+------------+
/// | # | Operands   |
/// +---+------------+
/// | 1 | Gpd, KReg  |
/// | 2 | KReg, Gpd  |
/// | 3 | KReg, KReg |
/// | 4 | KReg, Mem  |
/// | 5 | Mem, KReg  |
/// +---+------------+
/// ```
pub trait KmovwEmitter<A, B> {
    fn kmovw(&mut self, op0: A, op1: B);
}

impl<'a> KmovwEmitter<KReg, KReg> for Assembler<'a> {
    fn kmovw(&mut self, op0: KReg, op1: KReg) {
        self.emit(KMOVWKK, op0.as_operand(), op1.as_operand(), &NOREG, &NOREG);
    }
}

impl<'a> KmovwEmitter<KReg, Mem> for Assembler<'a> {
    fn kmovw(&mut self, op0: KReg, op1: Mem) {
        self.emit(KMOVWKM, op0.as_operand(), op1.as_operand(), &NOREG, &NOREG);
    }
}

impl<'a> KmovwEmitter<Mem, KReg> for Assembler<'a> {
    fn kmovw(&mut self, op0: Mem, op1: KReg) {
        self.emit(KMOVWMK, op0.as_operand(), op1.as_operand(), &NOREG, &NOREG);
    }
}

impl<'a> KmovwEmitter<KReg, Gpd> for Assembler<'a> {
    fn kmovw(&mut self, op0: KReg, op1: Gpd) {
        self.emit(KMOVWKR, op0.as_operand(), op1.as_operand(), &NOREG, &NOREG);
    }
}

impl<'a> KmovwEmitter<Gpd, KReg> for Assembler<'a> {
    fn kmovw(&mut self, op0: Gpd, op1: KReg) {
        self.emit(KMOVWRK, op0.as_operand(), op1.as_operand(), &NOREG, &NOREG);
    }
}

/// `KNOTW` (KNOTW). 
/// Performs a bitwise NOT of vector mask k2 and writes the result into vector mask k1.
///
///
/// For more details, see the [Intel manual](https://www.felixcloutier.com/x86/KNOTW%3AKNOTB%3AKNOTQ%3AKNOTD.html).
///
/// Supported operand variants:
