/// ```text
/// +---+------------+
/// | # | Operands   |
/// +---+------------+
/// | 1 | KReg, KReg |
/// +---+------------+
/// ```
pub trait KnotwEmitter<A, B> {
    fn knotw(&mut self, op0: A, op1: B);
}

impl<'a> KnotwEmitter<KReg, KReg> for Assembler<'a> {
    fn knotw(&mut self, op0: KReg, op1: KReg) {
        self.emit(KNOTWKK, op0.as_operand(), op1.as_operand(), &NOREG, &NOREG);
    }
}

/// `KORTESTW` (KORTESTW). 
/// Performs a bitwise OR between the vector mask register k2, and the vector mask register k1, and sets CF and ZF based on the operation result.
///
///
/// For more details, see the [Intel manual](https://www.felixcloutier.com/x86/KORTESTW%3AKORTESTB%3AKORTESTQ%3AKORTESTD.html).
///
/// Supported operand variants:
///
/// ```text
/// +---+------------+
/// | # | Operands   |
/// +---+------------+
/// | 1 | KReg, KReg |
/// +---+------------+
/// ```
