/// `VADDPD` (VADDPD). 
/// Adds two, four or eight packed double precision floating-point values from the first source operand to the second source operand, and stores the packed double precision floating-point result in the destination operand.
///
///
/// For more details, see the [Intel manual](https://www.felixcloutier.com/x86/ADDPD.html).
///
/// Supported operand variants:
///
/// ```text
/// +---+---------------+
/// | # | Operands      |
/// +---+---------------+
/// | 1 | Xmm, Xmm, Mem |
/// | 2 | Xmm, Xmm, Xmm |
/// | 3 | Ymm, Ymm, Mem |
/// | 4 | Ymm, Ymm, Ymm |
/// | 5 | Zmm, Zmm, Mem |
/// | 6 | Zmm, Zmm, Zmm |
/// +---+---------------+
/// ```
pub trait VaddpdEmitter<A, B, C> {
    fn vaddpd(&mut self, op0: A, op1: B, op2: C);
}

impl<'a> VaddpdEmitter<Xmm, Xmm, Xmm> for Assembler<'a> {
    fn vaddpd(&mut self, op0: Xmm, op1: Xmm, op2: Xmm) {
        self.emit(VADDPD128RRR, op0.as_operand(), op1.as_operand(), op2.as_operand(), &NOREG);
    }
}

impl<'a> VaddpdEmitter<Xmm, Xmm, Mem> for Assembler<'a> {
    fn vaddpd(&mut self, op0: Xmm, op1: Xmm, op2: Mem) {
        self.emit(VADDPD128RRM, op0.as_operand(), op1.as_operand(), op2.as_operand(), &NOREG);
    }
}

impl<'a> VaddpdEmitter<Ymm, Ymm, Ymm> for Assembler<'a> {
    fn vaddpd(&mut self, op0: Ymm, op1: Ymm, op2: Ymm) {
        self.emit(VADDPD256RRR, op0.as_operand(), op1.as_operand(), op2.as_operand(), &NOREG);
    }
}

impl<'a> VaddpdEmitter<Ymm, Ymm, Mem> for Assembler<'a> {
    fn vaddpd(&mut self, op0: Ymm, op1: Ymm, op2: Mem) {
        self.emit(VADDPD256RRM, op0.as_operand(), op1.as_operand(), op2.as_operand(), &NOREG);
    }
}

impl<'a> VaddpdEmitter<Zmm, Zmm, Zmm> for Assembler<'a> {
    fn vaddpd(&mut self, op0: Zmm, op1: Zmm, op2: Zmm) {
        self.emit(VADDPD512RRR, op0.as_operand(), op1.as_operand(), op2.as_operand(), &NOREG);
    }
}

impl<'a> VaddpdEmitter<Zmm, Zmm, Mem> for Assembler<'a> {
    fn vaddpd(&mut self, op0: Zmm, op1: Zmm, op2: Mem) {
        self.emit(VADDPD512RRM, op0.as_operand(), op1.as_operand(), op2.as_operand(), &NOREG);
    }
}

